const Web3 = require('web3');
const { ethers } = require('ethers');

// Configuration for Web3.js
const web3 = new Web3('https://mainnet.infura.io/v3/YOUR_INFURA_PROJECT_ID');
const privateKey = 'YOUR_PRIVATE_KEY';
const account = web3.eth.accounts.privateKeyToAccount(privateKey);
web3.eth.accounts.wallet.add(account);
web3.eth.defaultAccount = account.address;

// Function to send ETH using Web3.js
async function sendEthWeb3(to, amount) {
  const tx = {
    from: web3.eth.defaultAccount,
    to: to,
    value: web3.utils.toWei(amount, 'ether'),
    gas: 21000,
  };
  const txHash = await web3.eth.sendTransaction(tx);
  console.log('Transaction Hash:', txHash);
}

// Function to interact with a smart contract using Web3.js
async function interactWithContractWeb3(contractAddress, abi, method, args) {
  const contract = new web3.eth.Contract(abi, contractAddress);
  const data = contract.methods[method](...args).encodeABI();
  const tx = {
    from: web3.eth.defaultAccount,
    to: contractAddress,
    data: data,
    gas: 3000000,
  };
  const txHash = await web3.eth.sendTransaction(tx);
  console.log('Transaction Hash:', txHash);
}

// Configuration for ethers.js
const provider = new ethers.providers.InfuraProvider('mainnet', 'YOUR_INFURA_PROJECT_ID');
const wallet = new ethers.Wallet(privateKey, provider);

// Function to send ETH using ethers.js
async function sendEthEthers(to, amount) {
  const tx = {
    to: to,
    value: ethers.utils.parseEther(amount),
  };
  const txResponse = await wallet.sendTransaction(tx);
  console.log('Transaction Response:', txResponse);
}

// Function to interact with a smart contract using ethers.js
async function interactWithContractEthers(contractAddress, abi, method, args) {
  const contract = new ethers.Contract(contractAddress, abi, wallet);
  const tx = await contract[method](...args);
  console.log('Transaction Response:', tx);
}

// Example usage
